from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session

from app.api.deps import get_db
from app.schemas.housekeeping import ReportCreate, ReportResponse
from app.services import report_service

router = APIRouter(prefix="/reports")


@router.post("", response_model=ReportResponse, status_code=201)
def submit_report(data: ReportCreate, db: Session = Depends(get_db)):
    try:
        return report_service.create_report(db, data)
    except Exception as e:
        db.rollback()
        raise HTTPException(status_code=500, detail=str(e))


@router.get("", response_model=list[ReportResponse])
def get_reports(db: Session = Depends(get_db)):
    return report_service.list_reports(db)

