  flex-direction: column;
  align-items: center;
  gap: 10px;
  margin-bottom: 14px;
}

.btn-mic {
  width: 84px;
  height: 84px;
  border-radius: 50%;
  background: var(--blue-light);
  border: 3px solid var(--blue);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: transform 0.15s, background 0.2s, box-shadow 0.2s;
  box-shadow: 0 4px 16px rgba(74,144,255,0.2);
}
.btn-mic:active { transform: scale(0.94); }
.btn-mic.recording {
  background: #FEE2E2;
  border-color: var(--error);
  animation: pulse-mic 1.2s infinite;
}

@keyframes pulse-mic {
  0%, 100% { box-shadow: 0 0 0 0 rgba(239,68,68,0.4); }
  50%       { box-shadow: 0 0 0 14px rgba(239,68,68,0); }
}

.mic-icon { font-size: 36px; line-height: 1; }

.mic-status {
  font-size: 14px;
  font-weight: 700;
  color: var(--ink-3);
  transition: color 0.2s;
}
.mic-status.recording { color: var(--error); }

.voice-textarea {
  width: 100%;
  font-family: var(--font);
  font-size: 15px;
  font-weight: 400;
  color: var(--ink);
  background: var(--blue-xlight);
  border: 1.5px solid transparent;
  border-radius: var(--r-sm);
  padding: 12px;
  resize: none;
  outline: none;
  line-height: 1.5;
  transition: border-color 0.2s;
}
.voice-textarea:focus { border-color: var(--blue); }

/* Sticky bottom */
.sticky-bottom {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 12px var(--px) 24px;
  background: linear-gradient(to top, var(--bg) 75%, transparent);
  z-index: 20;
}

.btn-submit {
  height: 56px;
  font-size: 16px;
  font-weight: 900;
  letter-spacing: 1px;
}

/* ================================================================
   SCREEN 4 — SUCCESS
   ================================================================ */
#screen-success {
  background: linear-gradient(160deg, #EBF5FF 0%, #FFFFFF 100%);
  align-items: center;
  justify-content: center;
}

.success-inner {
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  padding: 40px var(--px);
  max-width: 360px;
  width: 100%;
}

.success-icon-wrap {
  position: relative;
  width: 120px;
  height: 120px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 28px;
}

.success-icon {
  width: 80px;
  height: 80px;
  border-radius: 50%;
  background: var(--success);
  color: #fff;
  font-size: 40px;
  font-weight: 900;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 8px 24px rgba(34,197,94,0.4);
  animation: pop-in 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) both;
  position: relative;
  z-index: 2;
}

@keyframes pop-in {
  from { transform: scale(0); opacity: 0; }
  to   { transform: scale(1); opacity: 1; }
}

.success-rings { position: absolute; inset: 0; }

.ring {
  position: absolute;
  border-radius: 50%;
  border: 2px solid var(--success);
  top: 50%; left: 50%;
  transform: translate(-50%, -50%) scale(0);
  opacity: 0;
}
.ring1 { width: 90px; height: 90px; animation: ring-out 1.4s 0.3s ease-out forwards; }
.ring2 { width: 110px; height: 110px; animation: ring-out 1.4s 0.55s ease-out forwards; }
.ring3 { width: 130px; height: 130px; animation: ring-out 1.4s 0.8s ease-out forwards; }

@keyframes ring-out {
  0%   { transform: translate(-50%,-50%) scale(0); opacity: 0.8; }
  100% { transform: translate(-50%,-50%) scale(1); opacity: 0; }
}

.success-title {
  font-size: 30px;
  font-weight: 900;
  color: var(--ink);
  line-height: 1.2;
  margin-bottom: 12px;
  letter-spacing: -0.5px;
}

.success-subtitle {
  font-size: 16px;
  font-weight: 600;
  color: var(--blue);
  margin-bottom: 16px;
  background: var(--blue-light);
  padding: 8px 20px;
  border-radius: var(--r-full);
}

.success-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 40px;
}
.meta-dot {
  width: 6px; height: 6px;
  border-radius: 50%;
  background: var(--success);
}
.meta-time { font-size: 14px; color: var(--ink-3); font-weight: 600; }

.btn-new {
  margin-bottom: 20px;
  font-size: 16px;
}

.redirect-hint {
  font-size: 13px;
  color: var(--ink-4);
  font-weight: 600;
}

/* ================================================================
   SPINNER
   ================================================================ */
.spinner {
  width: 22px;
  height: 22px;
  border: 3px solid rgba(255,255,255,0.4);
  border-top-color: #fff;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
  display: inline-block;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ================================================================
   MISC
   ================================================================ */
button { font-family: var(--font); }

/* Safe area insets for notched phones */
@supports (padding-bottom: env(safe-area-inset-bottom)) {
  .sticky-bottom { padding-bottom: calc(16px + env(safe-area-inset-bottom)); }
  .screen-inner  { padding-top: calc(48px + env(safe-area-inset-top)); }
}

