   BASE TEMPLATE — Clean structural foundation.
   The AI MUST replace this with a distinctive,
   project-specific design for each new app.
   ============================================ */

/* Reset */
*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

/* ============================================
   CSS VARIABLES — Placeholder structure.
   AI must define project-specific values for
   fonts, colors, spacing, and effects.
   ============================================ */
:root {
    /* Typography — AI MUST replace with distinctive Google Fonts */
    --font-display: sans-serif;
    --font-body: sans-serif;

    /* Colors — AI MUST define a unique, cohesive palette */
    --color-primary: #333;
    --color-background: #fff;
    --color-surface: #f5f5f5;
    --color-text: #111;
    --color-text-muted: #666;
    --color-border: #e0e0e0;
    --color-success: #22c55e;
    --color-error: #ef4444;
    --color-warning: #f59e0b;

    /* Spacing */
    --space-xs: 4px;
    --space-sm: 8px;
    --space-md: 12px;
    --space-lg: 16px;
    --space-xl: 24px;
    --space-2xl: 32px;
    --space-3xl: 48px;

    /* Border Radius */
    --radius-sm: 6px;
    --radius-md: 10px;
    --radius-lg: 16px;
    --radius-full: 999px;

    /* Transitions */
    --transition-fast: 150ms ease;
    --transition-normal: 250ms ease;
    --transition-slow: 400ms ease-out;
}

/* ============================================
   BASE LAYOUT
   ============================================ */

html, body {
    height: 100%;
    width: 100%;
    font-family: var(--font-body);
    color: var(--color-text);
    background: var(--color-background);
    line-height: 1.6;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

body {
    display: flex;
    flex-direction: column;
    min-height: 100vh;
}

main {
    flex: 1;
}

.container {
    width: 100%;
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 var(--space-lg);
}

@media (min-width: 640px) {
    .container { padding: 0 var(--space-xl); }
}

@media (min-width: 1024px) {
    .container { padding: 0 var(--space-2xl); }
}

/* ============================================
   FUNCTIONAL STATES (loading, error, empty)
   AI should restyle these to match the aesthetic.
   ============================================ */

.loading {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: var(--space-2xl);
}

.spinner {
    width: 24px;
    height: 24px;
    border: 3px solid var(--color-border);
    border-top-color: var(--color-primary);
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

.error-message {
    padding: var(--space-lg);
    border-radius: var(--radius-md);
    background: #fef2f2;
    color: var(--color-error);
    border: 1px solid var(--color-error);
    font-size: 14px;
}

.empty-state {
    text-align: center;
    padding: var(--space-2xl);
    color: var(--color-text-muted);
}

.form-error {
    color: var(--color-error);
    font-size: 12px;
    margin-top: var(--space-xs);
}

/* ============================================
   UTILITY CLASSES
   ============================================ */

/* Display */
.hidden { display: none !important; }
.flex { display: flex; }
.grid { display: grid; }

/* Flexbox */
.flex-col { flex-direction: column; }
.flex-row { flex-direction: row; }
.flex-wrap { flex-wrap: wrap; }
.items-start { align-items: flex-start; }
.items-center { align-items: center; }
.items-end { align-items: flex-end; }
.justify-start { justify-content: flex-start; }
.justify-center { justify-content: center; }
.justify-end { justify-content: flex-end; }
.justify-between { justify-content: space-between; }
.flex-1 { flex: 1; }

/* Gap */
.gap-1 { gap: var(--space-xs); }
.gap-2 { gap: var(--space-sm); }
.gap-3 { gap: var(--space-md); }
.gap-4 { gap: var(--space-lg); }
.gap-6 { gap: var(--space-xl); }

/* Spacing */
