/**
 * Housekeeping Report App
 * 4-screen SPA: Room Input → Camera → Report → Success
 */

// ── State ──────────────────────────────────────────────────────────
let state = {
  roomId: '',
  photos: [],      // Array of { dataUrl, blob }
  voiceNote: '',
  stream: null,    // MediaStream for camera
};

// ── Screen Navigation ──────────────────────────────────────────────
const screens = {
  room:    document.getElementById('screen-room'),
  camera:  document.getElementById('screen-camera'),
  report:  document.getElementById('screen-report'),
  success: document.getElementById('screen-success'),
};

function showScreen(name) {
  Object.entries(screens).forEach(([key, el]) => {
    if (key === name) {
      el.classList.remove('slide-out');
      el.classList.add('active');
    } else if (el.classList.contains('active')) {
      el.classList.add('slide-out');
      el.classList.remove('active');
    } else {
      el.classList.remove('active', 'slide-out');
    }
  });
}

// ── Toast ──────────────────────────────────────────────────────────
const toastEl = document.getElementById('toast');
let toastTimer;
function showToast(msg) {
  toastEl.textContent = msg;
  toastEl.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => toastEl.classList.remove('show'), 2800);
}

// ── Escape HTML ────────────────────────────────────────────────────
function escapeHtml(text) {
  const d = document.createElement('div');
  d.textContent = text;
  return d.innerHTML;
}

// ══════════════════════════════════════════════════════════════════
// SCREEN 1 — NHẬP MÃ PHÒNG
// ══════════════════════════════════════════════════════════════════
const roomInput   = document.getElementById('room-input');
const btnContinueRoom = document.getElementById('btn-continue-room');

roomInput.addEventListener('input', () => {
  btnContinueRoom.disabled = roomInput.value.trim().length === 0;
});

btnContinueRoom.addEventListener('click', () => {
  const id = roomInput.value.trim();
  if (!id) { showToast('Vui lòng nhập mã phòng'); return; }
  state.roomId = id;
  state.photos = [];
  goToCamera();
});

roomInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') btnContinueRoom.click();
});

// ══════════════════════════════════════════════════════════════════
// SCREEN 2 — CAMERA
// ══════════════════════════════════════════════════════════════════
const cameraRoomId      = document.getElementById('camera-room-id');
const photoCountEl      = document.getElementById('photo-count');
const videoEl           = document.getElementById('camera-video');
const canvasEl          = document.getElementById('camera-canvas');
const btnShutter        = document.getElementById('btn-shutter');
const thumbnailsRow     = document.getElementById('thumbnails-row');
const btnContinueCamera = document.getElementById('btn-continue-camera');
const cameraHint        = document.getElementById('camera-hint');
const btnBackCamera     = document.getElementById('btn-back-camera');

async function goToCamera() {
  cameraRoomId.textContent = state.roomId;
  showScreen('camera');
  await startCamera();
  renderThumbnails();
  updateCameraUI();
  // Auto-focus camera area
  setTimeout(() => btnShutter.focus(), 300);
}

async function startCamera() {
  if (state.stream) return; // already running
  try {
    state.stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: { ideal: 'environment' }, width: { ideal: 1280 }, height: { ideal: 720 } },
      audio: false,
    });
    videoEl.srcObject = state.stream;
  } catch (err) {
    console.warn('Camera not available:', err);
    showToast('Không thể truy cập camera. Kiểm tra quyền truy cập.');
  }
}

function stopCamera() {
  if (state.stream) {
    state.stream.getTracks().forEach(t => t.stop());
    state.stream = null;
    videoEl.srcObject = null;
  }
}

btnShutter.addEventListener('click', capturePhoto);

function capturePhoto() {
  if (state.photos.length >= 3) return;

  const w = videoEl.videoWidth  || 640;
  const h = videoEl.videoHeight || 480;
  canvasEl.width = w;
  canvasEl.height = h;

  const ctx = canvasEl.getContext('2d');
  ctx.drawImage(videoEl, 0, 0, w, h);

  canvasEl.toBlob((blob) => {
    const dataUrl = canvasEl.toDataURL('image/jpeg', 0.85);
    state.photos.push({ dataUrl, blob });
    renderThumbnails();
    updateCameraUI();

    if (state.photos.length === 3) {
      stopCamera();
      setTimeout(goToReport, 600);
    }
  }, 'image/jpeg', 0.85);
}

function renderThumbnails() {
  thumbnailsRow.innerHTML = '';

  state.photos.forEach((photo, idx) => {
    const wrap = document.createElement('div');
    wrap.className = 'thumb-wrap';

    const img = document.createElement('img');
    img.src = photo.dataUrl;
    img.alt = `Ảnh ${idx + 1}`;

    const del = document.createElement('button');
    del.className = 'thumb-delete';
    del.innerHTML = '✕';
    del.setAttribute('aria-label', `Xóa ảnh ${idx + 1}`);
    del.addEventListener('click', () => {
      state.photos.splice(idx, 1);
      renderThumbnails();
      updateCameraUI();
      // Restart camera if it was stopped
      if (!state.stream) startCamera();
    });

    wrap.appendChild(img);
    wrap.appendChild(del);
    thumbnailsRow.appendChild(wrap);
  });

  // Empty slots
  const remaining = 3 - state.photos.length;
  for (let i = 0; i < remaining; i++) {
    const slot = document.createElement('div');
    slot.className = 'thumb-add';
    slot.textContent = '+';
    thumbnailsRow.appendChild(slot);
  }
}

function updateCameraUI() {
  const count = state.photos.length;
  photoCountEl.textContent = count;

  btnShutter.disabled = count >= 3;
  if (count >= 3) {
    cameraHint.textContent = '✓ Đã chụp đủ 3 ảnh';
  } else {
    cameraHint.textContent = `Nhấn nút để chụp ảnh (${count}/3, tối thiểu 1)`;
  }

  // Show "Tiếp tục" only if 1 or 2 photos
  if (count >= 1 && count < 3) {
    btnContinueCamera.style.display = 'flex';
  } else {
    btnContinueCamera.style.display = 'none';
  }
}

btnContinueCamera.addEventListener('click', () => {
  if (state.photos.length < 1) { showToast('Vui lòng chụp ít nhất 1 ảnh'); return; }
  stopCamera();
  goToReport();
});

btnBackCamera.addEventListener('click', () => {
  stopCamera();
  showScreen('room');
});

// ══════════════════════════════════════════════════════════════════
// SCREEN 3 — REPORT
// ══════════════════════════════════════════════════════════════════
const reportRoomId = document.getElementById('report-room-id');
const reportImages = document.getElementById('report-images');
const btnMic       = document.getElementById('btn-mic');
const micStatus    = document.getElementById('mic-status');
const voiceText    = document.getElementById('voice-text');
const btnSubmit    = document.getElementById('btn-submit');
const submitText   = document.getElementById('submit-text');
const submitSpinner= document.getElementById('submit-spinner');
const btnBackReport= document.getElementById('btn-back-report');

let recognition = null;
let isRecording = false;

function goToReport() {
  reportRoomId.textContent = state.roomId;
  renderReportImages();
  showScreen('report');
}

function renderReportImages() {
  reportImages.innerHTML = state.photos.map((p, i) =>
    `<img class="report-thumb" src="${escapeHtml(p.dataUrl)}" alt="Ảnh ${i + 1}">`
  ).join('');
}

// Voice recording via Web Speech API
function setupSpeechRecognition() {
  const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SpeechRecognition) return null;

  const rec = new SpeechRecognition();
  rec.continuous = true;
  rec.interimResults = true;
  rec.lang = 'vi-VN';

  let finalTranscript = '';

  rec.onstart = () => {
    isRecording = true;
    btnMic.classList.add('recording');
    micStatus.textContent = '🔴 Đang ghi âm... (nhấn để dừng)';
    micStatus.classList.add('recording');
    finalTranscript = voiceText.value;
  };

  rec.onresult = (e) => {
    let interim = '';
    for (let i = e.resultIndex; i < e.results.length; i++) {
      const t = e.results[i].transcript;
      if (e.results[i].isFinal) finalTranscript += t + ' ';
      else interim += t;
    }
    voiceText.value = finalTranscript + interim;
  };

  rec.onend = () => {
    isRecording = false;
    btnMic.classList.remove('recording');
    micStatus.textContent = 'Nhấn để ghi âm';
    micStatus.classList.remove('recording');
    voiceText.value = voiceText.value.trim();
    state.voiceNote = voiceText.value;
  };

  rec.onerror = (e) => {
    console.warn('Speech error:', e.error);
    isRecording = false;
    btnMic.classList.remove('recording');
    micStatus.textContent = 'Nhấn để ghi âm';
    micStatus.classList.remove('recording');
    if (e.error === 'not-allowed') showToast('Cần quyền truy cập microphone');
    else showToast('Lỗi ghi âm, thử lại');
  };

  return rec;
}

btnMic.addEventListener('click', () => {
  if (!recognition) recognition = setupSpeechRecognition();

  if (!recognition) {
    showToast('Trình duyệt không hỗ trợ ghi âm. Nhập tay bên dưới.');
    voiceText.focus();
    return;
  }

  if (isRecording) {
    recognition.stop();
  } else {
    recognition.start();
  }
});

voiceText.addEventListener('input', () => {
  state.voiceNote = voiceText.value;
});

// Submit
btnSubmit.addEventListener('click', submitReport);

async function submitReport() {
  if (state.photos.length < 1) { showToast('Vui lòng chụp ít nhất 1 ảnh'); return; }

  // Stop recording if active
  if (isRecording && recognition) recognition.stop();

  setSubmitLoading(true);

  try {
    const imageUrls = await uploadPhotos();
    const payload = {
      room_id: state.roomId,
      image_urls: imageUrls,
      voice_note: voiceText.value.trim() || null,
    };

    await api.post('/api/reports', payload);
    goToSuccess();
  } catch (err) {
    console.error('Submit error:', err);
    showToast('Lỗi gửi báo cáo: ' + (err.message || 'Thử lại'));
    setSubmitLoading(false);
  }
}

function setSubmitLoading(loading) {
  btnSubmit.disabled = loading;
  submitText.style.display = loading ? 'none' : 'inline';
  submitSpinner.style.display = loading ? 'inline-block' : 'none';
}

async function uploadPhotos() {
  const urls = [];
  for (const photo of state.photos) {
    try {
      // Get presigned URL
      const filename = `housekeeping_${state.roomId}_${Date.now()}_${Math.random().toString(36).slice(2)}.jpg`;
      const { upload_url, file_url } = await api.post('/api/upload/presigned-url', { filename });

      // Upload to S3
      await fetch(upload_url, {
        method: 'PUT',
        body: photo.blob,
        headers: { 'Content-Type': 'image/jpeg' },
      });

      urls.push(file_url);
    } catch (err) {
      // If S3 upload fails (e.g., no S3 configured), store dataUrl as fallback
      console.warn('S3 upload failed, using dataUrl fallback:', err.message);
      urls.push(photo.dataUrl);
    }
  }
  return urls;
}

btnBackReport.addEventListener('click', () => {
  if (isRecording && recognition) recognition.stop();
  showScreen('camera');
  startCamera();
});

// ══════════════════════════════════════════════════════════════════
// SCREEN 4 — SUCCESS
// ══════════════════════════════════════════════════════════════════
const successRoomText = document.getElementById('success-room-text');
const successTime     = document.getElementById('success-time');
const btnNewRoom      = document.getElementById('btn-new-room');
const countdownEl     = document.getElementById('countdown');

let countdownTimer;

function goToSuccess() {
  successRoomText.textContent = `Phòng ${state.roomId} đã được ghi nhận`;
  successTime.textContent = new Date().toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' });
  setSubmitLoading(false);
  showScreen('success');
  startCountdown();
}

function startCountdown() {
  clearInterval(countdownTimer);
  let remaining = 3;
  countdownEl.textContent = remaining;
  countdownTimer = setInterval(() => {
    remaining--;
    countdownEl.textContent = remaining;
    if (remaining <= 0) {
      clearInterval(countdownTimer);
      resetToStart();
    }
  }, 1000);
}

function resetToStart() {
  clearInterval(countdownTimer);
  // Reset state
  state.roomId = '';
  state.photos = [];
  state.voiceNote = '';
  // Reset UI
  roomInput.value = '';
  btnContinueRoom.disabled = true;
  voiceText.value = '';
  showScreen('room');
  setTimeout(() => roomInput.focus(), 400);
}

btnNewRoom.addEventListener('click', () => {
  clearInterval(countdownTimer);
  resetToStart();
});

// ══════════════════════════════════════════════════════════════════
// INIT
// ══════════════════════════════════════════════════════════════════
document.addEventListener('DOMContentLoaded', () => {
  showScreen('room');
  setTimeout(() => roomInput.focus(), 300);
});

